// ============================================================================
// Tests: Implicit Gate Approval on @cody rerun
// Issue: When @cody rerun is triggered on a pipeline paused at a gate, the
// rerun should implicitly approve the gate instead of re-running the gated stage.
// ============================================================================

describe('Implicit gate approval on @cody rerun', () => {
  const FULL_PIPELINE = [
    'taskify',
    'spec',
    'gap',
    'clarify',
    'architect',
    'plan-gap',
    'build',
    'commit',
    'verify',
    'autofix',
    'pr',
  ]

  it('waiting branch should implicitly approve the gate and update state', () => {
    // This test verifies the expected behavior after the fix is applied.
    // Currently, the 'waiting' branch in entry.ts (lines 642-644) does nothing.
    // After the fix, it should call approveGate() which:
    // 1. Writes gate-{stage}-approved.md
    // 2. Calls resumeFromGate to mark stage as completed

    // Arrange: Pipeline paused at taskify gate (simulating handleGateApproval returning 'waiting')
    const pausedState = createBaseState({
      state: 'paused',
      completedAt: new Date().toISOString(),
      stages: {
        taskify: createStage('paused'),
      },
    })

    // Act: The fix should call resumeFromGate when gateResult === 'waiting'
    // This simulates what the fixed 'waiting' branch should do
    const approvedState = resumeFromGate(pausedState, 'taskify')

    // Assert: After implicit approval, the gate stage should be marked as completed
    expect(approvedState.stages['taskify'].state).toBe('completed')
    expect(approvedState.state).toBe('running')
  })

  it('fromStage should resolve to the next stage after implicit approval', () => {
    // After implicit approval, gateApprovedStage should be set so fromStage
    // resolves to the NEXT stage (not the gated stage itself).
    // This prevents resetFromStage from overwriting the approval.

    const nextStage = resolveFromStageAfterGateApproval('taskify', FULL_PIPELINE)

    // The next stage after taskify in full pipeline is 'spec'
    expect(nextStage).toBe('spec')
  })

  it('waiting branch should write approval file with implicit rerun message', () => {
    // This test verifies that when the 'waiting' branch implicitly approves,
    // the approval file should contain "implicitly approved via @cody rerun"
    // rather than "approved by user".

    // Arrange: The fix should write this message to gate-{stage}-approved.md
    const implicitApprovalMessage = 'implicitly approved via @cody rerun'
    const explicitApprovalMessage = 'approved by user'

    // Assert: The implicit approval message should be different from explicit
    // This test documents the expected behavior - the fix should use the implicit message
    expect(implicitApprovalMessage).not.toBe(explicitApprovalMessage)
    expect(implicitApprovalMessage).toContain('implicitly')
    expect(implicitApprovalMessage).toContain('rerun')
  })

  it('explicit approval should still work with user message', () => {
    // Regression test: Ensure that explicit @cody approve still works
    // after the refactor extracts approveGate() helper.

    // Arrange: Pipeline paused at taskify gate
    const pausedState = createBaseState({
      state: 'paused',
      stages: {
        taskify: createStage('paused'),
      },
    })

    // Act: Explicit approval (simulating handleGateApproval returning 'approved')
    const approvedState = resumeFromGate(pausedState, 'taskify')

    // Assert: Same state transition as implicit, but the approval file
    // should say "approved by user" (not "implicitly approved via @cody rerun")
    expect(approvedState.stages['taskify'].state).toBe('completed')
    expect(approvedState.state).toBe('running')
  })

  it('implicit approval preserves gate approval through resetFromStage', () => {
    // The key fix: when fromStage resolves to the NEXT stage (not the gate stage),
    // the gate approval should be preserved through resetFromStage.

    // Arrange: Pipeline with taskify paused, then implicit approval applied
    const pausedState = createBaseState({
      state: 'paused',
      stages: {
        taskify: createStage('paused'),
      },
    })

    // Act Step 1: Implicit approval marks taskify as completed
    const approvedState = resumeFromGate(pausedState, 'taskify')
    expect(approvedState.stages['taskify'].state).toBe('completed')

    // Act Step 2: fromStage resolves to next stage after taskify
    const nextStage = resolveFromStageAfterGateApproval('taskify', FULL_PIPELINE)
    expect(nextStage).toBe('spec')

    // Act Step 3: resetFromStage from the NEXT stage (not taskify!)
    const finalState = resetFromStage(approvedState, nextStage, FULL_PIPELINE, '/tmp/nonexistent-implicit')

    // Assert: taskify remains completed — gate approval is preserved!
    expect(finalState.stages['taskify'].state).toBe('completed')
    // And the pipeline continues from spec onwards
    expect(finalState.state).toBe('running')
  })
})

